#include <bits/stdc++.h>
using namespace std;
int main(){
    int n;
    cin>>n;
    long long a[n];
    for(int i=0;i<n;i++){
        cin>>a[i];
    }
    int ans=1,m=0;
    sort(a,a+n);
    for(int i=1;i<n;i++){
        if(a[i]-1==a[i-1]){
            m++;
        }
        else if(a[i]-1>a[i-1]){
            ans=max(ans,m+1);
            m=0;
        }
    }
    cout<<max(ans,m+1);
    return 0;
}
